#include <algorithm>
#include <queue>
#include <unordered_map>
#include <utility>

using namespace std;

long long solve(long long n, vector<vector<long long>> edges, long long k) {
    // Build the graph
    vector<vector<pair<long long, long long>>> graph(n);
    for (auto& edge : edges) {
        long long u = edge[0], v = edge[1], w = edge[2];
        graph[u].push_back({v, w});
        graph[v].push_back({u, w});
    }

    // Use a priority queue to process edges in order of increasing weight
    priority_queue<pair<long long, long long>, vector<pair<long long, long long>>, greater<pair<long long, long long>>> pq;
    // Use a visited array to track which nodes are processed
    vector<bool> visited(n, false);
    // Use a parent array to track the parent of each node in the MST
    vector<long long> parent(n, -1);
    // Use a size array to track the size of each component
    vector<long long> size(n, 1);

    // Initialize the priority queue with all edges
    for (long long u = 0; u < n; ++u) {
        for (auto& [v, w] : graph[u]) {
            pq.push({w, u, v});
        }
    }

    // Kruskal's algorithm to find the MST
    long long components = 0;
    long long max_cost = 0;
    while (!pq.empty()) {
        long long w = pq.top().first;
        long long u = pq.top().second;
        long long v = pq.top().third;
        pq.pop();

        if (visited[u] || visited[v]) continue;

        visited[u] = true;
        visited[v] = true;
        parent[v] = u;
        size[u] += size[v];

        // Check if the number of components is greater than k
        if (components + 1 > k) {
            max_cost = max(max_cost, w);
            break;
        }

        components++;
    }

    // If the number of components is less than k, the max cost is the maximum edge in the MST
    if (components < k) {
        max_cost = 0;
        for (long long i = 0; i < n; ++i) {
            if (parent[i] != -1) {
                max_cost = max(max_cost, size[i]);
            }
        }
    }

    return max_cost;
